 20→/// Creates CPI accounts, instruction data, and performs checks.
 21→/// - Merkle tree indices must be in order.
 22→/// - Hashes output accounts for insertion and event.
 23→/// - Collects sequence numbers for event.
 24→///
 25→/// Checks:
 26→/// 1. Checks whether a Merkle tree is program owned, if so checks write
 27→///    eligibility.
 28→/// 2. Checks ordering of Merkle tree indices.
 29→/// 3. Checks that addresses in output compressed accounts have been created or
 30→///    exist in input compressed accounts. An address may not be used in an
 31→///    output compressed accounts. This will close the account.
 32→#[allow(clippy::too_many_arguments)]
 33→#[allow(clippy::type_complexity)]
 34→#[profile]
 35→pub fn create_outputs_cpi_data<'a, 'info, T: InstructionData<'a>>(
 36→    inputs: &WrappedInstructionData<'a, T>,
 37→    remaining_accounts: &'info [AccountInfo],
 38→    context: &mut SystemContext<'info>,
 39→    cpi_ix_data: &mut InsertIntoQueuesInstructionDataMut<'_>,
 40→    accounts: &[AcpAccount<'info>],
 41→) -> Result<[u8; 32]> {
 42→    if inputs.output_len() == 0 {
 43→        return Ok([0u8; 32]);
 44→    }
 45→    let mut current_index: i16 = -1;
 46→    let mut num_leaves_in_tree: u32 = 0;
 47→    let mut mt_next_index: u32 = 0;
 48→    let mut hashed_merkle_tree = [0u8; 32];
 49→    cpi_ix_data.start_output_appends = context.account_indices.len() as u8;
 50→    let mut index_merkle_tree_account_account = cpi_ix_data.start_output_appends;
 51→    let mut index_merkle_tree_account = 0;
 52→    let number_of_merkle_trees =
 53→        inputs.output_accounts().last().unwrap().merkle_tree_index() as usize + 1;
 54→
 55→    let mut merkle_tree_pubkeys =
 56→        Vec::<light_compressed_account::pubkey::Pubkey>::with_capacity(number_of_merkle_trees);
 57→    let mut hash_chain = [0u8; 32];
 58→    let mut rollover_fee = 0;
 59→    let mut is_batched = true;
 60→
 61→    for (j, account) in inputs.output_accounts().enumerate() {
 62→        // if mt index == current index Merkle tree account info has already been added.
 63→        // if mt index != current index, Merkle tree account info is new, add it.
 64→        #[allow(clippy::comparison_chain)]
 65→        if account.merkle_tree_index() as i16 == current_index {
 66→            // Do nothing, but it is the most common case.
 67→        } else if account.merkle_tree_index() as i16 > current_index {
 68→            current_index = account.merkle_tree_index().into();
 69→
 70→            let pubkey = match &accounts
 71→                .get(current_index as usize)
 72→                .ok_or(SystemProgramError::OutputMerkleTreeIndexOutOfBounds)?
 73→            {
 74→                AcpAccount::OutputQueue(output_queue) => {
 75→                    context.set_network_fee_v2(
 76→                        output_queue.metadata.rollover_metadata.network_fee,
 77→                        current_index as u8,
 78→                    );
 79→
 80→                    hashed_merkle_tree = output_queue.hashed_merkle_tree_pubkey;
 81→                    rollover_fee = output_queue.metadata.rollover_metadata.rollover_fee;
 82→                    mt_next_index = output_queue.batch_metadata.next_index as u32;
 83→                    cpi_ix_data.output_sequence_numbers[index_merkle_tree_account as usize] =
 84→                        MerkleTreeSequenceNumber {
 85→                            tree_pubkey: output_queue.metadata.associated_merkle_tree,
 86→                            queue_pubkey: *output_queue.pubkey(),
 87→                            tree_type: (TreeType::StateV2 as u64).into(),
 88→                            seq: output_queue.batch_metadata.next_index.into(),
 89→                        };
 90→                    is_batched = true;
 91→                    *output_queue.pubkey()
 92→                }
 93→                AcpAccount::StateTree((pubkey, tree)) => {
 94→                    cpi_ix_data.output_sequence_numbers[index_merkle_tree_account as usize] =
 95→                        MerkleTreeSequenceNumber {
 96→                            tree_pubkey: *pubkey,
 97→                            queue_pubkey: *pubkey,
 98→                            tree_type: (TreeType::StateV1 as u64).into(),
 99→                            seq: (tree.sequence_number() as u64 + 1).into(),
100→                        };
101→                    let merkle_context = context
102→                        .get_legacy_merkle_context(current_index as u8)
103→                        .ok_or(SystemProgramError::MissingLegacyMerkleContext)?;
104→                    hashed_merkle_tree = merkle_context.hashed_pubkey;
105→                    rollover_fee = merkle_context.rollover_fee;
106→                    let network_fee = merkle_context.network_fee;
107→                    context.set_network_fee_v1(network_fee, current_index as u8)?;
108→                    mt_next_index = tree.next_index() as u32;
109→                    is_batched = false;
110→                    *pubkey
111→                }
112→                AcpAccount::Unknown() => {
113→                    msg!(
114→                        format!("found batched unknown create outputs {} ", current_index).as_str()
115→                    );
116→
117→                    return Err(
118→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
119→                    );
120→                }
121→                AcpAccount::BatchedAddressTree(_) => {
122→                    msg!(format!(
123→                        "found batched address tree create outputs {} ",
124→                        current_index
125→                    )
126→                    .as_str());
127→
128→                    return Err(
129→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
130→                    );
131→                }
132→                AcpAccount::BatchedStateTree(_) => {
133→                    msg!(
134→                        format!("found batched state tree create outputs {} ", current_index)
135→                            .as_str()
136→                    );
137→
138→                    return Err(
139→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
140→                    );
141→                }
142→                _ => {
143→                    msg!(format!("create outputs {} ", current_index).as_str());
144→
145→                    return Err(
146→                        SystemProgramError::StateMerkleTreeAccountDiscriminatorMismatch.into(),
147→                    );
148→                }
149→            };
150→            // check Merkle tree uniqueness
151→            if merkle_tree_pubkeys.contains(&pubkey) {
152→                return Err(SystemProgramError::OutputMerkleTreeNotUnique.into());
153→            } else {
154→                merkle_tree_pubkeys.push(pubkey);
155→            }
156→
157→            context.get_index_or_insert(
158→                account.merkle_tree_index(),
159→                remaining_accounts,
160→                "Output queue for V2 state trees (Merkle tree for V1 state trees)",
161→            )?;
162→            num_leaves_in_tree = 0;
163→            index_merkle_tree_account += 1;
164→            index_merkle_tree_account_account += 1;
165→        } else {
166→            // Check 2.
167→            // Output Merkle tree indices must be in order since we use the
168→            // number of leaves in a Merkle tree to determine the correct leaf
169→            // index. Since the leaf index is part of the hash this is security
170→            // critical.
171→            return Err(SystemProgramError::OutputMerkleTreeIndicesNotInOrder.into());
172→        }
173→
174→        // Check 3.
175→        if let Some(address) = account.address() {
176→            if let Some(position) = context.addresses.iter().position(|&x| x == Some(address)) {
177→                context.addresses.remove(position);
178→            } else {
179→                msg!(format!("context.addresses: {:?}", context.addresses).as_str());
180→                return Err(SystemProgramError::InvalidAddress.into());
181→            }
182→        }
183→        cpi_ix_data.output_leaf_indices[j] = (mt_next_index + num_leaves_in_tree).into();
184→
185→        num_leaves_in_tree += 1;
186→        if account.has_data() && context.invoking_program_id.is_none() {
187→            msg!("Invoking program is not provided.");
188→            msg!("Only program owned compressed accounts can have data.");
189→            return Err(SystemProgramError::InvokingProgramNotProvided.into());
190→        }
191→        let hashed_owner = match context
192→            .hashed_pubkeys
193→            .iter()
194→            .find(|x| x.0 == account.owner().to_bytes())
195→        {
196→            Some(hashed_owner) => hashed_owner.1,
197→            None => {
198→                let hashed_owner = hash_to_bn254_field_size_be(&account.owner().to_bytes());
199→                context
200→                    .hashed_pubkeys
201→                    .push((account.owner().into(), hashed_owner));
202→                hashed_owner
203→            }
204→        };
205→        // Compute output compressed account hash.
206→        cpi_ix_data.leaves[j].leaf = account
207→            .hash_with_hashed_values(
208→                &hashed_owner,
209→                &hashed_merkle_tree,
210→                &cpi_ix_data.output_leaf_indices[j].into(),
211→                is_batched,
212→            )
213→            .map_err(ProgramError::from)?;
214→        cpi_ix_data.leaves[j].account_index = index_merkle_tree_account_account - 1;
215→
216→        if !cpi_ix_data.nullifiers.is_empty() {
217→            if j == 0 {
218→                hash_chain = cpi_ix_data.leaves[j].leaf;
219→            } else {
220→                hash_chain = Poseidon::hashv(&[&hash_chain, &cpi_ix_data.leaves[j].leaf])
221→                    .map_err(ProgramError::from)?;
222→            }
223→        }
224→        context.set_rollover_fee(current_index as u8, rollover_fee);
225→    }
226→
227→    cpi_ix_data.num_output_queues = index_merkle_tree_account as u8;
228→    Ok(hash_chain)
229→}
