 1→use std::{fs::File, io::prelude::*, path::PathBuf};
 2→
 3→use clap::Parser;
 4→use light_hasher::{Hasher, Keccak, Poseidon, Sha256};
 5→use quote::quote;
 6→const MAX_HEIGHT: usize = 40;
 7→
 8→use crate::{utils::rustfmt, Hash};
 9→
10→#[derive(Debug, Parser)]
11→pub struct Options {
12→    #[clap(value_enum, long, default_value_t = Hash::Sha256)]
13→    hash: Hash,
14→    #[clap(long)]
15→    path: Option<PathBuf>,
16→}
17→
18→pub fn generate_zero_bytes(opts: Options) -> anyhow::Result<()> {
19→    match opts.hash {
20→        Hash::Keccak => generate_zero_bytes_for_hasher::<Keccak>(opts),
21→        Hash::Poseidon => generate_zero_bytes_for_hasher::<Poseidon>(opts),
22→        Hash::Sha256 => generate_zero_bytes_for_hasher::<Sha256>(opts),
23→    }
24→}
25→
26→fn generate_zero_bytes_for_hasher<H>(opts: Options) -> anyhow::Result<()>
27→where
28→    H: Hasher,
29→{
30→    let mut zero_bytes = [[0u8; 32]; MAX_HEIGHT + 1];
31→    let mut zero_bytes_tokens = vec![];
32→
33→    let mut prev_hash = H::hashv(&[&[0u8; 32], &[0u8; 32]]).unwrap();
34→    zero_bytes[1] = prev_hash;
35→
36→    for element in zero_bytes[2..].iter_mut() {
37→        let cur_hash = H::hashv(&[&prev_hash, &prev_hash]).unwrap();
38→        element.copy_from_slice(&cur_hash);
39→
40→        prev_hash = cur_hash;
41→    }
42→
43→    for element in zero_bytes.iter() {
44→        let element_iter = element.iter();
45→        zero_bytes_tokens.push(quote! {
46→            [ #(#element_iter),* ]
47→        });
48→    }
49→
50→    // NOTE(vadorovsky): I couldn't find any way to do a double repetition
51→    // over a 2D array inside `quote` macro, that's why arrays are converted
52→    // to tokens in the loop above. But I would be grateful if there is any
53→    // way to make it prettier.
54→    //
55→    // Being able to do something like:
56→    //
57→    // ```rust
58→    // let code = quote! {
59→    //     const ZERO_BYTES: ZeroBytes = [ #([ #(#zero_bytes),* ]),* ];
60→    // };
61→    // ```
62→    //
63→    // would be great.
64→    let code = quote! {
65→        use super::ZeroBytes;
66→
67→        pub const ZERO_BYTES: ZeroBytes = [ #(#zero_bytes_tokens),* ];
68→    };
69→
70→    println!(
71→        "Zero bytes (generated with {:?} hash): {:?}",
72→        opts.hash, zero_bytes
73→    );
74→
75→    if let Some(path) = opts.path {
76→        let mut file = File::create(&path)?;
77→        file.write_all(b"// This file is generated by xtask. Do not edit it manually.\n\n")?;
78→        file.write_all(&rustfmt(code.to_string())?)?;
79→        println!("Zero bytes written to {:?}", path);
80→    }
81→
82→    Ok(())
83→}
