 36→pub fn bigint_to_u8_32(n: &BigInt) -> Result<[u8; 32], Box<dyn std::error::Error>> {
 37→    let (_, bytes_be) = n.to_bytes_be();
 38→    if bytes_be.len() > 32 {
 39→        Err("Number too large to fit in [u8; 32]")?;
 40→    }
 41→    let mut array = [0; 32];
 42→    let bytes = &bytes_be[..bytes_be.len()];
 43→    array[(32 - bytes.len())..].copy_from_slice(bytes);
 44→    Ok(array)
 45→}
