 47→pub fn compute_root_from_merkle_proof<const HEIGHT: usize>(
 48→    leaf: [u8; 32],
 49→    path_elements: &[[u8; 32]; HEIGHT],
 50→    path_index: u32,
 51→) -> ([u8; 32], ChangelogEntry<HEIGHT>) {
 52→    let mut changelog_entry = ChangelogEntry::default_with_index(path_index as usize);
 53→
 54→    let mut current_hash = leaf;
 55→    let mut current_index = path_index;
 56→    for (level, path_element) in path_elements.iter().enumerate() {
 57→        changelog_entry.path[level] = Some(current_hash);
 58→        if current_index.is_multiple_of(2) {
 59→            current_hash = Poseidon::hashv(&[&current_hash, path_element]).unwrap();
 60→        } else {
 61→            current_hash = Poseidon::hashv(&[path_element, &current_hash]).unwrap();
 62→        }
 63→        current_index /= 2;
 64→    }
 65→
 66→    (current_hash, changelog_entry)
 67→}
