  1→use proc_macro2::TokenStream;
  2→use quote::quote;
  3→use syn::{Fields, ItemStruct, Result};
  4→
  5→use crate::hasher::{
  6→    data_hasher::{generate_data_hasher_impl, generate_data_hasher_impl_sha},
  7→    field_processor::{process_field, FieldProcessingContext},
  8→    input_validator::{get_field_attribute, validate_input, validate_input_sha, FieldAttribute},
  9→    to_byte_array::{generate_to_byte_array_impl_sha, generate_to_byte_array_impl_with_hasher},
 10→};
 11→
 12→/// - ToByteArray:
 13→///     1. ToByteArray -> [u8;32]
 14→///     2. ToByteArrays -> [[u8;32]; NUM_FIELDS]
 15→///     3. const NumFields -> usize (can be used to get ToByteArrays)
 16→/// - DataHasher Hash -> [u8;32]
 17→///
 18→/// - Attribute Macros:
 19→///     1. hash
 20→///        hash to bn254 field size (less than 254 bit), hash with keccak256 and truncate to 31 bytes
 21→///     2. skip
 22→///        ignore field
 23→///     3. flatten
 24→///        flatten nested struct or vector
 25→///
 26→/// Derive macro for ToByteArray
 27→/// - Struct:
 28→///   - every field must implement ToByteArray
 29→///   - impl ToByteArray for Struct -> returns hash of all fields
 30→///   - impl DataHasher for Struct -> returns hash of all fields
 31→/// - Options (primitive types PT):
 32→///     - Option<PT> -> [u8;32] -> Some: [32 - type_bytes_len..] 32 - index type_bytes_len -1 = [1] (BE prefix) , None: [0;32]
 33→/// - Option (General):
 34→///     - Option<T> T must implement Hash -> Some: Hash(T::hash), None: [0u8;32]
 35→/// - Nested Structs:
 36→///     - to_byte_array -> hash of all fields
 37→/// - Arrays (u8):
 38→///     1. LEN < 32 implementation of ToByteArray is provided
 39→///     2. LEN >= 32  needs to be handled (can be truncated or implement custom ToByteArray)
 40→/// - Arrays:
 41→///     1. if elements implement ToByteArray and are less than 13, hash of all elements
 42→///     2. More elements than 13 -> manual implementation or hash to field size
 43→/// - Vec<T>:
 44→///     - we do not provide a blanket implementation since it could fail in production once a vector fills up
 45→///     - users need to hash to field size or do a manual implementation
 46→/// - Strings:
 47→///     - we do not provide a blanket implementation since it could fail in production once a string fills up
 48→///     - users need to hash to field size or do a manual implementation
 49→/// - Enums, References, SmartPointers:
 50→///     - Not supported
 51→pub(crate) fn derive_light_hasher(input: ItemStruct) -> Result<TokenStream> {
 52→    derive_light_hasher_with_hasher(input, &quote!(::light_hasher::Poseidon))
 53→}
 54→
 55→pub(crate) fn derive_light_hasher_sha(input: ItemStruct) -> Result<TokenStream> {
 56→    // Use SHA256-specific validation (no field count limits)
 57→    validate_input_sha(&input)?;
 58→
 59→    let generics = input.generics.clone();
 60→
 61→    let fields = match &input.fields {
 62→        Fields::Named(fields) => fields.clone(),
 63→        _ => unreachable!("Validation should have caught this"),
 64→    };
 65→
 66→    let field_count = fields.named.len();
 67→
 68→    let to_byte_array_impl = generate_to_byte_array_impl_sha(&input.ident, &generics, field_count)?;
 69→    let data_hasher_impl = generate_data_hasher_impl_sha(&input.ident, &generics)?;
 70→
 71→    Ok(quote! {
 72→        #to_byte_array_impl
 73→
 74→        #data_hasher_impl
 75→    })
 76→}
 77→
 78→fn derive_light_hasher_with_hasher(input: ItemStruct, hasher: &TokenStream) -> Result<TokenStream> {
 79→    // Validate the input structure
 80→    validate_input(&input)?;
 81→
 82→    let generics = input.generics.clone();
 83→
 84→    // After validation, we know this is a named field struct
 85→    let fields = match &input.fields {
 86→        Fields::Named(fields) => fields.clone(),
 87→        _ => unreachable!("Validation should have caught this"),
 88→    };
 89→
 90→    let field_count = fields.named.len();
 91→    let flatten_field_exists = fields
 92→        .named
 93→        .iter()
 94→        .any(|field| get_field_attribute(field) == FieldAttribute::Flatten);
 95→
 96→    // Create processing context
 97→    let mut context = FieldProcessingContext::new(flatten_field_exists);
 98→
 99→    // Process each field
100→    fields.named.iter().enumerate().for_each(|(i, field)| {
101→        process_field(field, i, &mut context);
102→    });
103→
104→    let to_byte_array_impl = generate_to_byte_array_impl_with_hasher(
105→        &input.ident,
106→        &generics,
107→        field_count,
108→        &context,
109→        hasher,
110→    )?;
111→
112→    let data_hasher_impl = generate_data_hasher_impl(&input.ident, &generics, &context)?;
113→
114→    // Combine implementations
115→    Ok(quote! {
116→        #to_byte_array_impl
117→
118→        #data_hasher_impl
119→    })
120→}
