  1→use proc_macro2::TokenStream;
  2→use quote::quote;
  3→use syn::Result;
  4→
  5→use crate::hasher::field_processor::FieldProcessingContext;
  6→
  7→pub(crate) fn generate_data_hasher_impl(
  8→    struct_name: &syn::Ident,
  9→    generics: &syn::Generics,
 10→    context: &FieldProcessingContext,
 11→) -> Result<TokenStream> {
 12→    let (impl_gen, type_gen, where_clause) = generics.split_for_impl();
 13→
 14→    // Need to create references for the quote! macro
 15→    let hash_to_field_size_code = &context.hash_to_field_size_code;
 16→    let data_hasher_assignments = &context.data_hasher_assignments;
 17→    let flattened_fields_added = &context.flattened_fields_added;
 18→
 19→    let hasher_impl = if context.flatten_field_exists {
 20→        quote! {
 21→            impl #impl_gen ::light_hasher::DataHasher for #struct_name #type_gen #where_clause {
 22→                fn hash<H>(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError>
 23→                where
 24→                    H: ::light_hasher::Hasher
 25→                {
 26→                    use ::light_hasher::DataHasher;
 27→                    use ::light_hasher::Hasher;
 28→                    use ::light_hasher::to_byte_array::ToByteArray;
 29→
 30→                    #(#hash_to_field_size_code)*
 31→                    let mut num_flattned_fields = 0;
 32→                    let mut field_array = [[0u8; 32];  #(#flattened_fields_added)*];
 33→                    let mut slices: [&[u8]; #(#flattened_fields_added)*] = [&[];  #(#flattened_fields_added)*];
 34→
 35→
 36→                    for element in field_array.iter() {
 37→                        slices[num_flattned_fields] = element.as_slice();
 38→                    }
 39→
 40→                    let mut result = H::hashv(slices.as_slice())?;
 41→
 42→                    // Apply field size truncation for non-Poseidon hashers
 43→                    if H::ID != ::light_hasher::Poseidon::ID {
 44→                        result[0] = 0;
 45→                    }
 46→
 47→                    Ok(result)
 48→                }
 49→            }
 50→        }
 51→    } else {
 52→        quote! {
 53→            impl #impl_gen ::light_hasher::DataHasher for #struct_name #type_gen #where_clause {
 54→                fn hash<H>(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError>
 55→                where
 56→                    H: ::light_hasher::Hasher
 57→                {
 58→                    use ::light_hasher::DataHasher;
 59→                    use ::light_hasher::Hasher;
 60→                    use ::light_hasher::to_byte_array::ToByteArray;
 61→                    #(#hash_to_field_size_code)*
 62→                    #[cfg(debug_assertions)]
 63→                   {
 64→                       if std::env::var("RUST_BACKTRACE").is_ok() {
 65→                            let debug_prints: Vec<[u8;32]> = vec![#(#data_hasher_assignments,)*];
 66→                            println!("DataHasher::hash inputs {:?}", debug_prints);
 67→                       }
 68→                   }
 69→                    let mut result = H::hashv(&[
 70→                        #(#data_hasher_assignments.as_slice(),)*
 71→                    ])?;
 72→
 73→                    // Apply field size truncation for non-Poseidon hashers
 74→                    if H::ID != ::light_hasher::Poseidon::ID {
 75→                        result[0] = 0;
 76→                    }
 77→
 78→                    Ok(result)
 79→                }
 80→            }
 81→        }
 82→    };
 83→
 84→    Ok(hasher_impl)
 85→}
 86→
 87→/// SHA256-specific DataHasher implementation that serializes the whole struct
 88→pub(crate) fn generate_data_hasher_impl_sha(
 89→    struct_name: &syn::Ident,
 90→    generics: &syn::Generics,
 91→) -> Result<TokenStream> {
 92→    let (impl_gen, type_gen, where_clause) = generics.split_for_impl();
 93→
 94→    let hasher_impl = quote! {
 95→        impl #impl_gen ::light_hasher::DataHasher for #struct_name #type_gen #where_clause {
 96→            fn hash<H>(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError>
 97→            where
 98→                H: ::light_hasher::Hasher
 99→            {
100→                use ::light_hasher::Hasher;
101→                use borsh::BorshSerialize;
102→
103→                // Compile-time assertion that H must be SHA256 (ID = 1)
104→                use ::light_hasher::sha256::RequireSha256;
105→                let _ = <H as RequireSha256>::ASSERT;
106→
107→                // For SHA256, we serialize the whole struct and hash it in one go
108→                let serialized = self.try_to_vec().map_err(|_| ::light_hasher::HasherError::BorshError)?;
109→                let mut result = H::hash(&serialized)?;
110→                // Truncate sha256 to 31 be bytes less than 254 bits bn254 field size.
111→                result[0] = 0;
112→                Ok(result)
113→            }
114→        }
115→    };
116→
117→    Ok(hasher_impl)
118→}
