 1→use proc_macro2::TokenStream;
 2→use quote::quote;
 3→use syn::Result;
 4→
 5→use crate::hasher::field_processor::FieldProcessingContext;
 6→
 7→pub(crate) fn generate_to_byte_array_impl_with_hasher(
 8→    struct_name: &syn::Ident,
 9→    generics: &syn::Generics,
10→    field_count: usize,
11→    context: &FieldProcessingContext,
12→    hasher: &TokenStream,
13→) -> Result<TokenStream> {
14→    let (impl_gen, type_gen, where_clause) = generics.split_for_impl();
15→
16→    if field_count == 1 && !context.flatten_field_exists {
17→        let string = context.data_hasher_assignments[0].to_string();
18→        let alt_res = format!("Ok({})", string.as_str());
19→        // Removes clippy warning of unnessesary questionmark.
20→        let str = match string.strip_suffix("?") {
21→            Some(s) => s,
22→            None => &alt_res,
23→        };
24→
25→        let content: TokenStream = str.parse().expect("Invalid generated code");
26→        Ok(quote! {
27→            impl #impl_gen ::light_hasher::to_byte_array::ToByteArray for #struct_name #type_gen #where_clause {
28→                const NUM_FIELDS: usize = 1;
29→
30→                fn to_byte_array(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError> {
31→                    use ::light_hasher::to_byte_array::ToByteArray;
32→                    use ::light_hasher::hash_to_field_size::HashToFieldSize;
33→                    #content
34→                }
35→            }
36→        })
37→    } else {
38→        let data_hasher_assignments = &context.data_hasher_assignments;
39→        Ok(quote! {
40→            impl #impl_gen ::light_hasher::to_byte_array::ToByteArray for #struct_name #type_gen #where_clause {
41→                const NUM_FIELDS: usize = #field_count;
42→
43→                fn to_byte_array(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError> {
44→                    use ::light_hasher::to_byte_array::ToByteArray;
45→                    use ::light_hasher::hash_to_field_size::HashToFieldSize;
46→                    use ::light_hasher::Hasher;
47→                    let mut result = #hasher::hashv(&[
48→                        #(#data_hasher_assignments.as_slice(),)*
49→                    ])?;
50→
51→                    // Truncate field size for non-Poseidon hashers
52→                    if #hasher::ID != ::light_hasher::Poseidon::ID {
53→                        result[0] = 0;
54→                    }
55→
56→                    Ok(result)
57→                }
58→            }
59→        })
60→    }
61→}
