63→/// SHA256-specific ToByteArray implementation that serializes the whole struct
64→pub(crate) fn generate_to_byte_array_impl_sha(
65→    struct_name: &syn::Ident,
66→    generics: &syn::Generics,
67→    field_count: usize,
68→) -> Result<TokenStream> {
69→    let (impl_gen, type_gen, where_clause) = generics.split_for_impl();
70→
71→    Ok(quote! {
72→        impl #impl_gen ::light_hasher::to_byte_array::ToByteArray for #struct_name #type_gen #where_clause {
73→            const NUM_FIELDS: usize = #field_count;
74→
75→            fn to_byte_array(&self) -> ::std::result::Result<[u8; 32], ::light_hasher::HasherError> {
76→                use borsh::BorshSerialize;
77→                use ::light_hasher::Hasher;
78→
79→                // For SHA256, we can serialize the whole struct and hash it in one go
80→                let serialized = self.try_to_vec().map_err(|_| ::light_hasher::HasherError::BorshError)?;
81→                let mut result = ::light_hasher::Sha256::hash(&serialized)?;
82→
83→                // Truncate field size for SHA256
84→                result[0] = 0;
85→
86→                Ok(result)
87→            }
88→        }
89→    })
90→}
