 59→pub fn process_create_pda<'info>(
 60→    ctx: Context<'_, '_, '_, 'info, CreateCompressedPda<'info>>,
 61→    data: [u8; 31],
 62→    proof: Option<CompressedProof>,
 63→    new_address_params: NewAddressParamsPacked,
 64→    owner_program: Pubkey,
 65→    cpi_context: Option<CompressedCpiContext>,
 66→    mode: CreatePdaMode,
 67→    bump: u8,
 68→    read_only_address: Option<Vec<PackedReadOnlyAddress>>,
 69→    read_only_accounts: Option<Vec<PackedReadOnlyCompressedAccount>>,
 70→    input_accounts: Option<Vec<PackedCompressedAccountWithMerkleContext>>,
 71→) -> Result<()> {
 72→    let compressed_pda = create_compressed_pda_data(
 73→        data,
 74→        &ctx,
 75→        &new_address_params,
 76→        &owner_program,
 77→        mode.clone(),
 78→    )?;
 79→
 80→    match mode {
 81→        CreatePdaMode::ProgramIsNotSigner => {
 82→            cpi_compressed_pda_transfer_as_non_program(
 83→                &ctx,
 84→                proof,
 85→                new_address_params,
 86→                compressed_pda,
 87→                cpi_context,
 88→            )?;
 89→        }
 90→        // functional test
 91→        CreatePdaMode::ProgramIsSigner
 92→        | CreatePdaMode::BatchAddressFunctional
 93→        | CreatePdaMode::InvalidBatchTreeAccount
 94→        | CreatePdaMode::OneReadOnlyAddress
 95→        | CreatePdaMode::TwoReadOnlyAddresses
 96→        | CreatePdaMode::InvalidReadOnlyAddress
 97→        | CreatePdaMode::InvalidReadOnlyRootIndex
 98→        | CreatePdaMode::InvalidReadOnlyMerkleTree
 99→        | CreatePdaMode::UseReadOnlyAddressInAccount
100→        | CreatePdaMode::ReadOnlyProofOfInsertedAddress
101→        | CreatePdaMode::InvalidReadOnlyAccount
102→        | CreatePdaMode::InvalidReadOnlyAccountRootIndex
103→        | CreatePdaMode::InvalidReadOnlyAccountMerkleTree
104→        | CreatePdaMode::ReadOnlyProofOfInsertedAccount
105→        | CreatePdaMode::BatchFunctional
106→        | CreatePdaMode::Functional
107→        | CreatePdaMode::InvalidProofReadOnlyAccount
108→        | CreatePdaMode::InvalidReadOnlyAccountOutputQueue
109→        | CreatePdaMode::ProofIsNoneReadOnlyAccount
110→        | CreatePdaMode::AccountNotInValueVecMarkedProofByIndex
111→        | CreatePdaMode::InvalidLeafIndex
112→        | CreatePdaMode::ReadOnlyZkpOfInsertedAccount => {
113→            cpi_compressed_pda_transfer_as_program(
114→                &ctx,
115→                proof,
116→                new_address_params,
117→                compressed_pda,
118→                cpi_context,
119→                bump,
120→                read_only_address,
121→                read_only_accounts,
122→                input_accounts,
123→                mode,
124→            )?;
125→        }
126→        CreatePdaMode::InvalidSignerSeeds => {
127→            cpi_compressed_pda_transfer_as_program(
128→                &ctx,
129→                proof,
130→                new_address_params,
131→                compressed_pda,
132→                cpi_context,
133→                bump,
134→                read_only_address,
135→                None,
136→                None,
137→                CreatePdaMode::InvalidSignerSeeds,
138→            )?;
139→        }
140→        CreatePdaMode::InvalidInvokingProgram => {
