233→fn cpi_compressed_pda_transfer_as_program<'info>(
234→    ctx: &Context<'_, '_, '_, 'info, CreateCompressedPda<'info>>,
235→    proof: Option<CompressedProof>,
236→    new_address_params: NewAddressParamsPacked,
237→    compressed_pda: OutputCompressedAccountWithPackedContext,
238→    cpi_context: Option<CompressedCpiContext>,
239→    bump: u8,
240→    mut read_only_address: Option<Vec<PackedReadOnlyAddress>>,
241→    mut read_only_accounts: Option<Vec<PackedReadOnlyCompressedAccount>>,
242→    input_accounts: Option<Vec<PackedCompressedAccountWithMerkleContext>>,
243→    mode: CreatePdaMode,
244→) -> Result<()> {
245→    let invoking_program = match mode {
246→        CreatePdaMode::InvalidInvokingProgram => ctx.accounts.signer.to_account_info(),
247→        _ => ctx.accounts.self_program.to_account_info(),
248→    };
249→    let compressed_pda = match mode {
250→        CreatePdaMode::WriteToAccountNotOwned => {
251→            // account with data needs to be owned by the program
252→            let mut compressed_pda = compressed_pda;
253→            compressed_pda.compressed_account.owner = ctx.accounts.signer.key().into();
254→            compressed_pda
255→        }
256→        CreatePdaMode::NoData => {
257→            let mut compressed_pda = compressed_pda;
258→
259→            compressed_pda.compressed_account.data = None;
260→            compressed_pda
261→        }
262→        CreatePdaMode::UseReadOnlyAddressInAccount => {
263→            let mut compressed_pda = compressed_pda;
264→            compressed_pda.compressed_account.address =
265→                Some(read_only_address.as_ref().unwrap()[0].address);
266→            compressed_pda
267→        }
268→        _ => compressed_pda,
269→    };
270→
271→    let mut inputs_struct = InstructionDataInvokeCpi {
272→        relay_fee: None,
273→        input_compressed_accounts_with_merkle_context: input_accounts.unwrap_or_default(),
274→        output_compressed_accounts: vec![compressed_pda],
275→        proof,
276→        new_address_params: vec![new_address_params],
277→        compress_or_decompress_lamports: None,
278→        is_compress: false,
279→        cpi_context,
280→    };
281→    // defining seeds again so that the cpi doesn't fail we want to test the check in the compressed pda program
282→    let seeds: [&[u8]; 2] = [CPI_AUTHORITY_PDA_SEED, &[bump]];
283→    msg!("read only address {:?}", read_only_address);
284→    msg!("read only accounts {:?}", read_only_accounts);
285→    if read_only_address.is_some() || read_only_accounts.is_some() {
286→        if mode == CreatePdaMode::ReadOnlyProofOfInsertedAddress {
287→            let read_only_address = read_only_address.as_mut().unwrap();
288→            read_only_address[0].address = inputs_struct.output_compressed_accounts[0]
289→                .compressed_account
290→                .address
291→                .unwrap();
292→        }
293→        // We currently only support two addresses hence we need to remove the
294→        // account and address to make space for two read only addresses.
295→        if mode == CreatePdaMode::TwoReadOnlyAddresses {
296→            inputs_struct.output_compressed_accounts = vec![];
297→            inputs_struct.new_address_params = vec![];
298→        }
299→        let mut remaining_accounts = ctx.remaining_accounts.to_vec();
300→
301→        if let Some(read_only_address) = &mut read_only_address {
302→            match mode {
303→                CreatePdaMode::InvalidReadOnlyMerkleTree => {
304→                    remaining_accounts.push(ctx.accounts.registered_program_pda.to_account_info());
305→                    msg!(
306→                        "read_only_address[0].address_merkle_tree_account_index {:?}",
307→                        read_only_address[0].address_merkle_tree_account_index
308→                    );
309→                    read_only_address[0].address_merkle_tree_account_index =
310→                        (remaining_accounts.len() - 1) as u8;
311→                    msg!(
312→                        "read_only_address[0].address_merkle_tree_account_index {:?}",
313→                        read_only_address[0].address_merkle_tree_account_index
314→                    );
315→                }
316→                CreatePdaMode::InvalidReadOnlyRootIndex => {
317→                    read_only_address[0].address_merkle_tree_root_index = 1;
318→                }
319→                CreatePdaMode::InvalidReadOnlyAddress => {
320→                    read_only_address[0].address = [0; 32];
321→                }
322→                _ => {}
323→            }
324→        }
325→        if let Some(read_only_account) = &mut read_only_accounts {
326→            match mode {
327→                CreatePdaMode::InvalidReadOnlyAccountMerkleTree => {
328→                    read_only_account[0].merkle_context.merkle_tree_pubkey_index =
329→                        read_only_account[0].merkle_context.queue_pubkey_index;
330→                }
331→                CreatePdaMode::InvalidReadOnlyAccountRootIndex => {
332→                    let init_value = read_only_account[0].root_index;
333→                    read_only_account[0].root_index =
334→                        read_only_account[0].root_index.saturating_sub(1);
335→                    if read_only_account[0].root_index == init_value {
336→                        read_only_account[0].root_index =
337→                            read_only_account[0].root_index.saturating_add(1);
338→                    }
339→                }
340→                CreatePdaMode::InvalidReadOnlyAccount => {
341→                    read_only_account[0].account_hash = [0; 32];
342→                }
343→                CreatePdaMode::ProofIsNoneReadOnlyAccount => {
344→                    inputs_struct.proof = None;
345→                }
346→                CreatePdaMode::InvalidProofReadOnlyAccount => {
347→                    inputs_struct.proof = Some(CompressedProof::default());
348→                }
349→                CreatePdaMode::InvalidReadOnlyAccountOutputQueue => {
350→                    read_only_account[0].merkle_context.queue_pubkey_index =
351→                        read_only_account[0].merkle_context.merkle_tree_pubkey_index;
352→                }
353→                CreatePdaMode::AccountNotInValueVecMarkedProofByIndex => {
354→                    if read_only_account[0].merkle_context.prove_by_index {
355→                        panic!("Queue index shouldn't be set for mode AccountNotInValueVecMarkedProofByIndex");
356→                    }
357→                    read_only_account[0].merkle_context.prove_by_index = true;
358→                }
359→                CreatePdaMode::InvalidLeafIndex => {
360→                    read_only_account[0].merkle_context.leaf_index += 1;
361→                }
362→                CreatePdaMode::ReadOnlyProofOfInsertedAccount => {
363→                    inputs_struct.new_address_params = vec![];
364→                    inputs_struct.output_compressed_accounts = vec![];
365→                    inputs_struct.proof = None;
366→                }
367→                CreatePdaMode::ReadOnlyZkpOfInsertedAccount => {
368→                    inputs_struct.new_address_params = vec![];
369→                    inputs_struct.output_compressed_accounts = vec![];
370→                }
371→                _ => {}
372→            }
373→        }
374→
375→        msg!("read_only_address {:?}", read_only_address);
376→        let inputs_struct = InstructionDataInvokeCpiWithReadOnly {
377→            mode: 0,
378→            bump,
379→            with_transaction_hash: true,
380→            with_cpi_context: inputs_struct.cpi_context.is_some(),
381→            invoking_program_id: crate::ID.into(),
382→            proof: inputs_struct.proof,
383→            // Should fail because of this.
384→            new_address_params: inputs_struct
385→                .new_address_params
386→                .iter()
387→                .enumerate()
388→                .map(|(i, x)| NewAddressParamsAssignedPacked::new(*x, Some(i as u8)))
389→                .collect::<Vec<_>>(),
390→            cpi_context: inputs_struct.cpi_context.unwrap_or_default(),
391→            is_compress: inputs_struct.is_compress,
392→            compress_or_decompress_lamports: inputs_struct
393→                .compress_or_decompress_lamports
394→                .unwrap_or_default(),
395→            output_compressed_accounts: inputs_struct.output_compressed_accounts,
396→            input_compressed_accounts: inputs_struct
397→                .input_compressed_accounts_with_merkle_context
398→                .iter()
399→                .map(|x| InAccount {
400→                    address: x.compressed_account.address,
401→                    merkle_context: x.merkle_context,
402→                    lamports: x.compressed_account.lamports,
403→                    discriminator: x.compressed_account.data.as_ref().unwrap().discriminator,
404→                    data_hash: x.compressed_account.data.as_ref().unwrap().data_hash,
405→                    root_index: x.root_index,
406→                })
407→                .collect::<Vec<_>>(),
408→            read_only_addresses: read_only_address.unwrap_or_default(),
409→            read_only_accounts: read_only_accounts.unwrap_or_default(),
410→        };
411→
412→        let cpi_accounts = light_system_program::cpi::accounts::InvokeCpiInstruction {
413→            fee_payer: ctx.accounts.signer.to_account_info(),
414→            authority: ctx.accounts.cpi_signer.to_account_info(),
415→            registered_program_pda: ctx.accounts.registered_program_pda.to_account_info(),
416→            noop_program: ctx.accounts.noop_program.to_account_info(),
417→            account_compression_authority: ctx
418→                .accounts
419→                .account_compression_authority
420→                .to_account_info(),
421→            account_compression_program: ctx.accounts.account_compression_program.to_account_info(),
422→            invoking_program,
423→            sol_pool_pda: None,
424→            decompression_recipient: None,
425→            system_program: ctx.accounts.system_program.to_account_info(),
426→            cpi_context_account: None,
427→        };
428→
429→        let signer_seeds: [&[&[u8]]; 1] = [&seeds[..]];
430→
431→        let mut cpi_ctx = CpiContext::new_with_signer(
432→            ctx.accounts.light_system_program.to_account_info(),
433→            cpi_accounts,
434→            &signer_seeds,
435→        );
436→
437→        cpi_ctx.remaining_accounts = remaining_accounts;
438→
439→        light_system_program::cpi::invoke_cpi_with_read_only(cpi_ctx, inputs_struct)?;
440→    } else {
441→        let cpi_accounts = light_system_program::cpi::accounts::InvokeCpiInstruction {
442→            fee_payer: ctx.accounts.signer.to_account_info(),
443→            authority: ctx.accounts.cpi_signer.to_account_info(),
444→            registered_program_pda: ctx.accounts.registered_program_pda.to_account_info(),
445→            noop_program: ctx.accounts.noop_program.to_account_info(),
446→            account_compression_authority: ctx
447→                .accounts
448→                .account_compression_authority
449→                .to_account_info(),
450→            account_compression_program: ctx.accounts.account_compression_program.to_account_info(),
451→            invoking_program,
452→            sol_pool_pda: None,
453→            decompression_recipient: None,
454→            system_program: ctx.accounts.system_program.to_account_info(),
455→            cpi_context_account: None,
456→        };
457→
458→        let signer_seeds: [&[&[u8]]; 1] = [&seeds[..]];
459→
460→        let mut cpi_ctx = CpiContext::new_with_signer(
461→            ctx.accounts.light_system_program.to_account_info(),
462→            cpi_accounts,
463→            &signer_seeds,
464→        );
465→
466→        cpi_ctx.remaining_accounts = ctx.remaining_accounts.to_vec();
467→
468→        light_system_program::cpi::invoke_cpi(cpi_ctx, inputs_struct.try_to_vec().unwrap())?;
469→    }
470→    Ok(())
471→}
