473→fn create_compressed_pda_data(
474→    data: [u8; 31],
475→    ctx: &Context<'_, '_, '_, '_, CreateCompressedPda<'_>>,
476→    new_address_params: &NewAddressParamsPacked,
477→    owner_program: &Pubkey,
478→    mode: CreatePdaMode,
479→) -> Result<OutputCompressedAccountWithPackedContext> {
480→    let timelock_compressed_pda = RegisteredUser {
481→        user_pubkey: *ctx.accounts.signer.key,
482→        data,
483→    };
484→    let compressed_account_data = CompressedAccountData {
485→        discriminator: 1u64.to_le_bytes(),
486→        data: timelock_compressed_pda.try_to_vec().unwrap(),
487→        data_hash: timelock_compressed_pda.hash::<Poseidon>().unwrap(),
488→    };
489→    let discriminator_bytes = &ctx.remaining_accounts
490→        [new_address_params.address_merkle_tree_account_index as usize]
491→        .try_borrow_data()?[0..8];
492→
493→    let address = match discriminator_bytes {
494→        AddressMerkleTreeAccount::DISCRIMINATOR => derive_address_legacy(
495→            &ctx.remaining_accounts[new_address_params.address_merkle_tree_account_index as usize]
496→                .key()
497→                .into(),
498→            &new_address_params.seed,
499→        )
500→        .unwrap(),
501→        BatchedMerkleTreeAccount::LIGHT_DISCRIMINATOR_SLICE => derive_address(
502→            &new_address_params.seed,
503→            &ctx.remaining_accounts[new_address_params.address_merkle_tree_account_index as usize]
504→                .key()
505→                .to_bytes(),
506→            &crate::ID.to_bytes(),
507→        ),
508→        _ => {
509→            if mode == CreatePdaMode::InvalidBatchTreeAccount {
510→                derive_address(
511→                    &new_address_params.seed,
512→                    &ctx.remaining_accounts
513→                        [new_address_params.address_merkle_tree_account_index as usize]
514→                        .key()
515→                        .to_bytes(),
516→                    &crate::ID.to_bytes(),
517→                )
518→            } else {
519→                panic!("Invalid discriminator");
520→            }
521→        }
522→    };
523→
524→    Ok(OutputCompressedAccountWithPackedContext {
525→        compressed_account: CompressedAccount {
526→            owner: owner_program.into(), // should be crate::ID, test can provide an invalid owner
527→            lamports: 0,
528→            address: Some(address),
529→            data: Some(compressed_account_data),
530→        },
531→        merkle_tree_index: 0,
532→    })
533→}
