541→impl light_hasher::DataHasher for RegisteredUser {
542→    fn hash<H: light_hasher::Hasher>(&self) -> std::result::Result<[u8; 32], HasherError> {
543→        let truncated_user_pubkey = hash_to_bn254_field_size_be(&self.user_pubkey.to_bytes());
544→        let mut data_bytes = [0u8; 32];
545→        data_bytes[1..].copy_from_slice(&self.data);
546→        H::hashv(&[truncated_user_pubkey.as_slice(), &data_bytes])
547→    }
548→}
