 26→/// Generic prepare_account_for_compression.
 27→///
 28→/// Called by the dispatch function after it has:
 29→/// 1. Read the discriminator from the account
 30→/// 2. Deserialized the account data
 31→///
 32→/// Pushes CompressedAccountInfo into ctx.compressed_account_infos.
 33→/// Pushes pda_index into ctx.pda_indices_to_close.
 34→///
 35→/// # Arguments
 36→/// * `account_info` - The PDA account to compress
 37→/// * `account_data` - Deserialized account data (will be modified to mark as compressed)
 38→/// * `compressed_account_meta` - Compressed account metadata
 39→/// * `pda_index` - Index of the PDA in the accounts array (for tracking closes)
 40→/// * `ctx` - Mutable context ref - pushes results here
 41→pub fn prepare_account_for_compression<AI, A>(
 42→    account_info: &AI,
 43→    account_data: &mut A,
 44→    compressed_account_meta: &CompressedAccountMetaNoLamportsNoAddress,
 45→    pda_index: usize,
 46→    ctx: &mut CompressCtx<'_, AI>,
 47→) -> Result<(), LightSdkTypesError>
 48→where
 49→    AI: AccountInfoTrait,
 50→    A: HasCompressionInfo + LightDiscriminator + Clone + borsh::BorshSerialize,
 51→{
 52→    // v2 address derive using PDA as seed
 53→    let account_key = account_info.key();
 54→    let derived_c_pda = derive_address(
 55→        &account_key,
 56→        &ctx.light_config.address_space[0],
 57→        ctx.program_id,
 58→    );
 59→
 60→    let meta_with_address = CompressedAccountMeta {
 61→        tree_info: compressed_account_meta.tree_info,
 62→        address: derived_c_pda,
 63→        output_state_tree_index: compressed_account_meta.output_state_tree_index,
 64→    };
 65→
 66→    let current_slot = AI::get_current_slot().map_err(LightSdkTypesError::AccountError)?;
 67→    let bytes = account_info.data_len() as u64;
 68→    let current_lamports = account_info.lamports();
 69→    let rent_exemption_lamports =
 70→        AI::get_min_rent_balance(bytes as usize).map_err(LightSdkTypesError::AccountError)?;
 71→
 72→    let ci = account_data.compression_info()?;
 73→    let last_claimed_slot = ci.last_claimed_slot();
 74→    let rent_cfg = ci.rent_config;
 75→
 76→    let state = AccountRentState {
 77→        num_bytes: bytes,
 78→        current_slot,
 79→        current_lamports,
 80→        last_claimed_slot,
 81→    };
 82→
 83→    // Check if account is compressible by rent function
 84→    if state
 85→        .is_compressible(&rent_cfg, rent_exemption_lamports)
 86→        .is_none()
 87→    {
 88→        ctx.has_non_compressible = true;
 89→        return Ok(());
 90→    }
 91→
 92→    // Mark as compressed
 93→    account_data.compression_info_mut()?.set_compressed();
 94→
 95→    // Serialize updated account data back (includes discriminator prefix)
 96→    {
 97→        let mut data = account_info
 98→            .try_borrow_mut_data()
 99→            .map_err(LightSdkTypesError::AccountError)?;
100→        // Write discriminator first (variable length: LIGHT_DISCRIMINATOR_SLICE may be < 8 bytes)
101→        let disc_slice = A::LIGHT_DISCRIMINATOR_SLICE;
102→        let disc_len = disc_slice.len();
103→        data[..disc_len].copy_from_slice(disc_slice);
104→        // Write serialized account data after discriminator
105→        let writer = &mut &mut data[disc_len..];
106→        account_data
107→            .serialize(writer)
108→            .map_err(|_| LightSdkTypesError::Borsh)?;
109→    }
110→
111→    // Create compressed account with canonical compressed CompressionInfo for hashing
112→    let mut compressed_data = account_data.clone();
113→    *compressed_data.compression_info_mut()? =
114→        crate::interface::account::compression_info::CompressionInfo::compressed();
115→
116→    // Hash the data (discriminator NOT included per protocol convention)
117→    let data_bytes = borsh::to_vec(&compressed_data).map_err(|_| LightSdkTypesError::Borsh)?;
118→    let mut output_data_hash = Sha256::hash(&data_bytes).map_err(LightSdkTypesError::Hasher)?;
119→    output_data_hash[0] = 0; // Zero first byte per protocol convention
120→
121→    // Build input account info (placeholder compressed account from init)
122→    // The init created a placeholder with DECOMPRESSED_PDA_DISCRIMINATOR and PDA pubkey as data
123→    let tree_info = compressed_account_meta.tree_info;
124→    let input_data_hash = Sha256BE::hash(&account_key).map_err(LightSdkTypesError::Hasher)?;
125→    let input_account_info = InAccountInfo {
126→        data_hash: input_data_hash,
127→        lamports: 0,
128→        merkle_context: PackedMerkleContext {
129→            merkle_tree_pubkey_index: tree_info.merkle_tree_pubkey_index,
130→            queue_pubkey_index: tree_info.queue_pubkey_index,
131→            leaf_index: tree_info.leaf_index,
132→            prove_by_index: tree_info.prove_by_index,
133→        },
134→        root_index: compressed_account_meta.get_root_index().unwrap_or_default(),
135→        discriminator: DECOMPRESSED_PDA_DISCRIMINATOR,
136→    };
137→
138→    // Build output account info
139→    let output_account_info = OutAccountInfo {
140→        lamports: 0,
141→        output_merkle_tree_index: meta_with_address.output_state_tree_index,
142→        discriminator: A::LIGHT_DISCRIMINATOR,
143→        data: data_bytes,
144→        data_hash: output_data_hash,
145→    };
146→
147→    // Push to ctx's internal vecs
148→    ctx.compressed_account_infos.push(CompressedAccountInfo {
149→        address: Some(meta_with_address.address),
150→        input: Some(input_account_info),
151→        output: Some(output_account_info),
152→    });
153→    ctx.pda_indices_to_close.push(pda_index);
154→
155→    Ok(())
156→}
